import{_ as e,o,c as a,a2 as l}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"徐灵胎","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/05-徐灵胎.md","filePath":"tcm-data/04-明清/05-徐灵胎.md","lastUpdated":1781084559000}'),r={name:"tcm-data/04-明清/05-徐灵胎.md"};function n(s,t,i,d,h,g){return o(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="徐灵胎" tabindex="-1">徐灵胎 <a class="header-anchor" href="#徐灵胎" aria-label="Permalink to &quot;徐灵胎&quot;">​</a></h1><blockquote><p>徐灵胎（1693-1771年），江苏吴江人 清代医学批评家，实证主义大师 代表作：《医学源流论》《慎疾刍言》《兰台轨范》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：名大椿，字灵胎，号洄溪老人</li><li><strong>生平</strong>：自20岁始，苦攻《内经》《伤寒》《金匮》十年，通晓天文、地理、数学、水利、音律</li><li><strong>性格</strong>：以批评时医著称，言辞犀利</li><li><strong>学术地位</strong>：<strong>清代最务实的医家</strong>，&quot;实证主义&quot;的代表</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-用药如用兵" tabindex="-1">1. 用药如用兵 <a class="header-anchor" href="#_1-用药如用兵" aria-label="Permalink to &quot;1. 用药如用兵&quot;">​</a></h3><blockquote><p><strong>「用药如用兵，实实虚虚之祸，不可不察。」</strong></p></blockquote><p>徐灵胎将治病比作用兵——需要了解&quot;敌情&quot;（病位、病性）、选择&quot;将领&quot;（君药）、部署&quot;兵力&quot;（佐使）。</p><h3 id="_2-医非人人可学" tabindex="-1">2. 医非人人可学 <a class="header-anchor" href="#_2-医非人人可学" aria-label="Permalink to &quot;2. 医非人人可学&quot;">​</a></h3><blockquote><p><strong>「医者，生命所系。非聪明特达、博学通方者，不可为医。」</strong></p></blockquote><h3 id="_3-病有不必治" tabindex="-1">3. 病有不必治 <a class="header-anchor" href="#_3-病有不必治" aria-label="Permalink to &quot;3. 病有不必治&quot;">​</a></h3><blockquote><p><strong>「天下有皆不治之病而可治者也，有皆可治之病而不治者也。」</strong></p></blockquote><p>他认为有些疾病不需要干预，人体自愈力足够；有些疾病即使治疗也无法逆转——<strong>医生的智慧在于分辨这两者。</strong></p><h3 id="_4-源流论" tabindex="-1">4. 源流论 <a class="header-anchor" href="#_4-源流论" aria-label="Permalink to &quot;4. 源流论&quot;">​</a></h3><p>《医学源流论》是徐灵胎最著名的著作，他梳理了中医各流派的源流关系，指出：</p><ul><li><strong>《内经》</strong>：万法之源</li><li><strong>《伤寒论》</strong>：辨证之祖</li><li><strong>唐宋以后</strong>：源流混乱，良莠不齐</li></ul><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><p>徐灵胎不像其他医家那样创立大量新方，而是以<strong>精选经方</strong>著称。他编著的《兰台轨范》选取了最实用的一批经方时方。</p><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">主治</th><th style="text-align:left;">徐灵胎评语</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>桂枝汤</strong></td><td style="text-align:left;">太阳中风</td><td style="text-align:left;">「此方为群方之冠」</td></tr><tr><td style="text-align:left;"><strong>小柴胡汤</strong></td><td style="text-align:left;">少阳病</td><td style="text-align:left;">「神方也」</td></tr><tr><td style="text-align:left;"><strong>四逆汤</strong></td><td style="text-align:left;">少阴寒化</td><td style="text-align:left;">「此回阳第一方」</td></tr><tr><td style="text-align:left;"><strong>肾气丸</strong></td><td style="text-align:left;">肾虚</td><td style="text-align:left;">「补而不滞，温而不燥」</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「用药如用兵。」</strong></p></blockquote><blockquote><p><strong>「医者，生命所系。」</strong></p></blockquote><blockquote><p><strong>「医非人人可学，非聪明特达者不可为。」</strong></p></blockquote><blockquote><p><strong>「病有不必治者，有不可治者，有不可不治者。」</strong></p></blockquote><blockquote><p><strong>「三里之市，必有良医；百户之邑，必有善药。」</strong></p></blockquote><blockquote><p><strong>「庸医杀人，不必用刀。」</strong></p></blockquote><blockquote><p><strong>「凡治病，必先辨明病之所在，而后治之。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>徐灵胎的批评精神影响了黄元御（两人同一时代，黄元御也以批评时医著称）</li><li>其实证主义的治学态度是现代中医循证医学的先声</li><li>《医学源流论》至今是中医入门必读书之一</li></ul><hr><p><em>本条目为精简框架版。</em></p>',36)])])}const q=e(r,[["render",n]]);export{c as __pageData,q as default};
